const data = $json;

const maxTemp = data.daily.temperature_2m_max[0];
const minTemp = data.daily.temperature_2m_min[0];
const precipitation = data.daily.precipitation_sum[0];
const windSpeed = data.daily.windspeed_10m_max[0];
const date = data.daily.time[0];

const dateObj = new Date(date);
const options = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' };
const turkishDate = dateObj.toLocaleDateString('tr-TR', options);

const warnings = [];

if (minTemp < 2) {
  warnings.push(`🥶 DON UYARISI!\nGece sıcaklığı ${minTemp}°C'ye düşecek.\nBitkilerinizi koruyun, borularınızı kontrol edin!`);
}

if (maxTemp > 38) {
  warnings.push(`🔥 AŞIRI SICAK UYARISI!\nGündüz sıcaklığı ${maxTemp}°C'ye çıkacak.\nBol su için, güneşten korunun!`);
}

if (precipitation > 10) {
  warnings.push(`🌧️ YAĞMUR UYARISI!\nBeklenen yağış: ${precipitation} mm\nŞemsiyenizi almayı unutmayın!`);
}

if (windSpeed > 50) {
  warnings.push(`🌪️ FIRTINA UYARISI!\nRüzgar hızı: ${windSpeed} km/s\nDışarıda dikkatli olun, gevşek eşyaları sabitleyin!`);
}

let message = '';

if (warnings.length > 0) {
  message = `⚠️ GAZİANTEP HAVA DURUMU UYARI ⚠️\n`;
  message += `📅 ${turkishDate}\n`;
  message += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  message += warnings.join('\n\n');
  message += `\n\n━━━━━━━━━━━━━━━━━━━━━\n`;
  message += `📊 Günlük Özet:\n`;
  message += `🌡️ Sıcaklık: ${minTemp}°C / ${maxTemp}°C\n`;
  message += `🌧️ Yağış: ${precipitation} mm\n`;
  message += `💨 Rüzgar: ${windSpeed} km/s`;
} else {
  message = `☀️ GAZİANTEP GÜNLÜK HAVA DURUMU\n`;
  message += `📅 ${turkishDate}\n`;
  message += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  message += `✅ Bugün için herhangi bir uyarı bulunmuyor.\n\n`;
  message += `🌡️ En Düşük: ${minTemp}°C\n`;
  message += `🌡️ En Yüksek: ${maxTemp}°C\n`;
  message += `🌧️ Yağış: ${precipitation} mm\n`;
  message += `💨 Rüzgar: ${windSpeed} km/s\n\n`;
  message += `İyi günler! 🌤️`;
}

return [{ json: { message, warnings: warnings.length, maxTemp, minTemp, precipitation, windSpeed } }];
